2138	// matchesWhere returns true if the bead satisfies all key=value predicates.
2139	// It checks known struct fields first, then falls back to Extra.
2140	func matchesWhere(b Bead, where map[string]string) bool {
2141		for k, v := range where {
2142			var actual string
2143			switch k {
2144			case "id":
2145				actual = b.ID
2146			case "title":
2147				actual = b.Title
2148			case "status":
2149				actual = b.Status
2150			case "issue_type":
2151				actual = b.IssueType
2152			case "owner":
2153				actual = b.Owner
2154			case "assignee":
2155				actual = b.Owner
2156			case "parent":
2157				actual = b.Parent
2158			case "description":
2159				actual = b.Description
2160			case "acceptance":
2161				actual = b.Acceptance
2162			case "notes":
2163				actual = b.Notes
2164			default:
2165				// Fall back to Extra map for unknown/workflow-specific fields
2166				if b.Extra != nil {
2167					if ev, ok := b.Extra[k]; ok {
2168						actual = fmt.Sprintf("%v", ev)
2169					}
2170				}
2171			}
2172			if actual != v {
2173				return false
2174			}
2175		}
