2191	func (s *Store) classifyLifecycleQueue(beads []Bead, now time.Time) []lifecycleQueueEntry {
2192		statusMap := make(map[string]string)
2193		childCount := make(map[string]int)
2194		openChildCount := make(map[string]int)
2195		for _, b := range beads {
2196			statusMap[b.ID] = b.Status
2197			if b.Parent != "" {
2198				childCount[b.Parent]++
2199				if b.Status != StatusClosed {
2200					openChildCount[b.Parent]++
2201				}
2202			}
2203		}
2204	
2205		// Read origin HEAD once per pass for rev-bound cooldown auto-invalidation.
2206		originHead := originMainHead(s.workingDir())
2207	
2208		entries := make([]lifecycleQueueEntry, 0, len(beads))
2209		for _, b := range beads {
2210			unclosed := unclosedDependencyIDs(b, statusMap)
2211			retryAfter, retryActive := activeRetryCooldown(b, now, originHead)
2212			executionEligible, executionEligibleKnown := lifecycleExecutionEligible(b)
2213			supersededBy := lifecycleSupersededBy(b)
2214			claimFresh := (b.Status == StatusOpen || b.Status == StatusInProgress) && !claimLeaseIsStale(s, b.Extra, b.ID)
2215			entry := lifecycleQueueEntry{
2216				Bead:                 b,
2217				UnclosedDepIDs:       unclosed,
2218				RetryAfter:           retryAfter,
2219				LastStatus:           extraStringVal(b.Extra, ExtraLastStatus),
2220				LastDetail:           extraStringVal(b.Extra, ExtraLastDetail),
2221				ExecutionSkipReason:  extraStringVal(b.Extra, ExtraExecutionReason),
2222				SupersededBy:         supersededBy,
2223				EpicClosureCandidate: isEpicClosureCandidate(b, openChildCount[b.ID], childCount[b.ID]),
2224			}
2225			entry.Decision = EvaluateLifecycleQueue(LifecycleQueueFacts{
2226				Status:                 b.Status,
2227				Dependencies:           lifecycleDependencyStates(b, statusMap),
2228				ClaimFresh:             claimFresh,
2229				RetryCooldownActive:    retryActive,
2230				ExecutionEligible:      executionEligible,
2231				ExecutionEligibleKnown: executionEligibleKnown,
2232				SupersededBy:           supersededBy,
2233				EpicContainer:          isOrdinaryEpicContainer(b, openChildCount[b.ID], childCount[b.ID]),
2234				ExternalBlockerReason:  extraStringVal(b.Extra, ExtraLifecycleExternalBlockerReason),
2235				LegacyLabels:           b.Labels,
2236			})
2237			entries = append(entries, entry)
2238		}
2239		return entries
2240	}
