2264	// activeRetryCooldown returns the retry-after time and whether the cooldown is
2265	// still active for bead b. When work-cooldown-base-rev is set and
2266	// originHead has advanced past that rev (i.e., originHead != baseRev and both
2267	// are non-empty), the cooldown auto-clears regardless of wall-clock expiry —
2268	// the world-state that caused the cooldown has changed. See TD-031 §5 invariant.
2269	// originHead should be the current origin/main HEAD, read once per
2270	// ready-queue evaluation pass (not per bead).
2271	func activeRetryCooldown(b Bead, now time.Time, originHead string) (time.Time, bool) {
2272		retryAfterStr := extraStringVal(b.Extra, ExtraRetryAfter)
2273		if retryAfterStr == "" {
2274			return time.Time{}, false
2275		}
2276		retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
2277		if err != nil {
2278			return time.Time{}, false
2279		}
2280		// Rev-bound auto-invalidation: if origin/main has advanced since this
2281		// cooldown was set, the fix may already be in and the cooldown should clear.
2282		baseRev := extraStringVal(b.Extra, ExtraCooldownBaseRev)
2283		if baseRev != "" && originHead != "" && originHead != baseRev {
2284			return time.Time{}, false
2285		}
2286		return retryAfter, retryAfter.After(now)
2287	}
