2481	func isHumanReviewBlocker(b Bead) bool {
2482		// Post-lifecycle: proposed status is the canonical operator-attention signal.
2483		if b.Status == StatusProposed {
2484			return true
2485		}
2486		// Legacy: open beads with investigation/human-review labels still count.
2487		if b.Status != StatusOpen {
2488			return false
2489		}
2490		for _, label := range b.Labels {
2491			switch label {
2492			case LabelNeedsHuman, LabelNeedsInvestigation, LabelNoChangesUnverified, LabelNoChangesUnjustified:
2493				return true
2494			}
2495		}
2496		return false
2497	}
