2691	//     the container bucket so the work-loop layer can diagnose it separately.
2692	func isOrdinaryEpicContainer(b Bead, openChildCount, totalChildCount int) bool {
2693		issueType := strings.ToLower(strings.TrimSpace(b.IssueType))
2694		title := strings.ToLower(strings.TrimSpace(b.Title))
2695		explicitEpic := issueType == "epic" || strings.HasPrefix(title, "epic:")
2696		looseEpic := strings.HasPrefix(title, "epic ") && totalChildCount > 0
2697		if !explicitEpic && !looseEpic {
2698			return false
2699		}
2700		return totalChildCount > 0
2701	}
