2710	func sortBeadsForQueue(beads []Bead) {
2711		sort.SliceStable(beads, func(i, j int) bool {
2712			if beads[i].Priority != beads[j].Priority {
2713				return beads[i].Priority < beads[j].Priority
2714			}
2715			ir, iok := parseQueueRank(beads[i].Extra["queue-rank"])
2716			jr, jok := parseQueueRank(beads[j].Extra["queue-rank"])
2717			if iok != jok {
2718				return iok
2719			}
2720			if iok && jok && ir != jr {
2721				return ir < jr
2722			}
2723			if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
2724				return beads[i].CreatedAt.Before(beads[j].CreatedAt)
2725			}
2726			return beads[i].ID < beads[j].ID
2727		})
2728	}
