2781		workerReady, err := s.ReadyExecution()
2782		if err != nil {
2783			return nil, err
2784		}
2785		needsHuman, err := s.ProposedOperatorAttention()
2786		if err != nil {
2787			return nil, err
2788		}
2789	
2790		// Pull in archive partner so totals survive `bead migrate` — the archive
2791		// only carries closed beads, so Ready/Blocked aren't affected.
2792		seen := make(map[string]bool, len(beads))
2793		all := make([]Bead, 0, len(beads))
2794		for _, b := range beads {
2795			if seen[b.ID] {
2796				continue
2797			}
2798			seen[b.ID] = true
2799			all = append(all, b)
2800		}
2801		if s.Collection == DefaultCollection {
2802			archive := s.archivePartner()
2803			if archived, aerr := archive.ReadAll(context.Background()); aerr == nil {
2804				for _, b := range archived {
2805					if seen[b.ID] {
2806						continue
2807					}
2808					seen[b.ID] = true
2809					all = append(all, b)
2810				}
2811			}
2812		}
2813	
2814		counts := &StatusCounts{
2815			Total:             len(all),
2816			Ready:             len(ready),
2817			WorkerReady:       len(workerReady),
2818			NeedsHuman:        len(needsHuman),
2819			OperatorAttention: len(needsHuman),
2820		}
2821		for _, b := range all {
2822			switch b.Status {
2823			case StatusOpen:
2824				counts.Open++
2825			case StatusInProgress:
2826				counts.InProgress++
2827			case StatusClosed:
2828				counts.Closed++
2829			case StatusBlocked:
2830				counts.Blocked++
2831			case StatusProposed:
2832				counts.Proposed++
2833			case StatusCancelled:
2834				counts.Cancelled++
2835			}
2836		}
2837		for _, entry := range s.classifyLifecycleQueue(beads, time.Now().UTC()) {
2838			switch entry.Decision.Bucket {
2839			case LifecycleBucketWaitingDependencies:
2840				counts.DependencyWaiting++
2841			case LifecycleBucketBlockedExternal:
2842				counts.ExternalBlocked++
