2848	// DepAdd adds a dependency: id depends on depID.
2849	func (s *Store) DepAdd(id, depID string) error {
2850		return s.WithLock(func() error {
2851			beads, _, err := s.readAllLatestRaw()
2852			if err != nil {
2853				return err
2854			}
2855			var target *Bead
2856			depExists := false
2857			for i := range beads {
2858				if beads[i].ID == id {
2859					target = &beads[i]
2860				}
2861				if beads[i].ID == depID {
2862					depExists = true
2863				}
2864			}
2865			if target == nil {
2866				return fmt.Errorf("bead: not found: %s", id)
2867			}
2868			if !depExists {
2869				return fmt.Errorf("bead: dependency not found: %s", depID)
2870			}
2871			if id == depID {
2872				return fmt.Errorf("bead: cannot depend on self")
2873			}
2874			if target.HasDep(depID) {
2875				return nil // already exists
2876			}
2877	
2878			// Check for circular dependency
2879			depMap := make(map[string][]string)
2880			for _, b := range beads {
2881				depMap[b.ID] = b.DepIDs()
2882			}
2883			depMap[id] = append(append([]string{}, target.DepIDs()...), depID)
2884			if hasCycle(depMap, id) {
2885				return fmt.Errorf("bead: circular dependency: %s -> %s", id, depID)
2886			}
2887	
2888			target.AddDep(depID, "blocks")
2889			target.UpdatedAt = time.Now().UTC()
2890			return s.WriteAll(beads)
2891		})
2892	}
