2901	// DepTree returns a text representation of the dependency tree.
2902	func (s *Store) DepTree(rootID string) (string, error) {
2903		beads, err := s.ReadAll(context.Background())
2904		if err != nil {
2905			return "", err
2906		}
2907		// Pull in archive partner so the tree survives `bead migrate` — closed
2908		// beads stored only in the archive must still appear.
2909		if s.Collection == DefaultCollection {
2910			archive := s.archivePartner()
2911			if archived, aerr := archive.ReadAll(context.Background()); aerr == nil {
2912				seen := make(map[string]bool, len(beads))
2913				for _, b := range beads {
2914					seen[b.ID] = true
2915				}
2916				for _, b := range archived {
2917					if seen[b.ID] {
2918						continue
2919					}
2920					beads = append(beads, b)
2921				}
2922			}
2923		}
2924		byID := make(map[string]*Bead)
2925		for i := range beads {
2926			byID[beads[i].ID] = &beads[i]
2927		}
2928	
2929		if rootID != "" {
2930			target, ok := byID[rootID]
2931			if !ok {
2932				return "", fmt.Errorf("bead: not found: %s", rootID)
2933			}
2934			var sb strings.Builder
2935			// Walk up: show the dependency chain (what this node depends on)
2936			depChain := s.depChainUp(byID, rootID)
2937			if len(depChain) > 0 {
2938				// Print deps as the tree root(s), with the target as their child
2939				for _, depID := range depChain {
2940					if dep, ok := byID[depID]; ok {
2941						fmt.Fprintf(&sb, "%s [%s] %s\n", dep.ID, dep.Status, dep.Title)
2942					}
2943				}
2944			}
2945			// Print the target node
2946			fmt.Fprintf(&sb, "%s [%s] %s\n", target.ID, target.Status, target.Title)
2947			// Print dependents (what depends on this node)
2948			var children []string
2949			for _, other := range sortedKeys(byID) {
2950				if byID[other].HasDep(rootID) {
2951					children = append(children, other)
2952				}
2953			}
2954			for _, child := range children {
2955				s.printTree(&sb, byID, child, "  ", true)
2956			}
2957			return sb.String(), nil
2958		}
2959	
2960		// Find roots (beads that have no dependencies themselves)
2961		var roots []string
2962		for _, b := range beads {
2963			if len(b.Dependencies) == 0 {
2964				roots = append(roots, b.ID)
2965			}
2966		}
2967		sort.Strings(roots)
2968	
2969		var sb strings.Builder
2970		for i, root := range roots {
2971			s.printTree(&sb, byID, root, "", i == len(roots)-1)
2972		}
2973		return sb.String(), nil
2974	}
2975	
2976	func (s *Store) printTree(sb *strings.Builder, byID map[string]*Bead, id, prefix string, last bool) {
2977		b, ok := byID[id]
2978		if !ok {
2979			return
2980		}
2981	
2982		connector := "├── "
2983		if last {
2984			connector = "└── "
2985		}
2986		if prefix == "" {
2987			connector = ""
2988		}
2989	
2990		fmt.Fprintf(sb, "%s%s%s [%s] %s\n", prefix, connector, b.ID, b.Status, b.Title)
2991	
2992		// Find beads that depend on this one (children in the tree)
2993		var children []string
2994		for _, other := range sortedKeys(byID) {
2995			if byID[other].HasDep(id) {
2996				children = append(children, other)
2997			}
2998		}
2999	
3000		childPrefix := prefix
3001		if prefix != "" {
3002			if last {
3003				childPrefix += "    "
3004			} else {
3005				childPrefix += "│   "
3006			}
3007		}
3008	
3009		for i, child := range children {
3010			s.printTree(sb, byID, child, childPrefix, i == len(children)-1)
3011		}
3012	}
