3043	// detectPrefix derives the bead ID prefix from the repository/directory name,
3044	// following the bd convention (e.g., repo "my-project" → prefix "my-project").
3045	// workingDir is the project root to use for git commands; when empty the
3046	// process working directory is used (legacy behaviour, prone to worktree
3047	// path contamination). Falls back to DefaultPrefix if detection fails.
3048	func detectPrefix(workingDir string) string {
3049		// Try git repo root name first, running from the known project root so
3050		// that linked worktrees (e.g. execute-bead isolated worktrees) do not
3051		// contaminate the prefix with their ephemeral directory names.
3052		cmd := gitpkg.Command(context.Background(), workingDir, "rev-parse", "--show-toplevel")
3053		if out, err := cmd.Output(); err == nil {
3054			root := strings.TrimSpace(string(out))
3055			if root != "" {
3056				return filepath.Base(root)
3057			}
3058		}
3059		// Fall back to the provided working dir, then cwd.
3060		if workingDir != "" {
3061			return filepath.Base(workingDir)
3062		}
3063		if wd, err := os.Getwd(); err == nil {
3064			return filepath.Base(wd)
3065		}
3066		return DefaultPrefix
3067	}
