3134	// hasCycle detects cycles in the dependency graph starting from startID.
3135	func hasCycle(deps map[string][]string, startID string) bool {
3136		visited := make(map[string]bool)
3137		stack := make(map[string]bool)
3138	
3139		var visit func(string) bool
3140		visit = func(id string) bool {
3141			visited[id] = true
3142			stack[id] = true
3143	
3144			for _, dep := range deps[id] {
3145				if !visited[dep] {
3146					if visit(dep) {
3147						return true
3148					}
3149				} else if stack[dep] {
3150					return true
3151				}
3152			}
3153	
3154			stack[id] = false
3155			return false
3156		}
3157	
3158		return visit(startID)
3159	}
