158	// GetWithArchive resolves a bead ID across the active collection and the
159	// archive partner, with active-wins precedence. This is the lookup the
160	// `ddx bead show` command uses so a closed-and-archived bead remains
161	// addressable by ID.
162	func (s *Store) GetWithArchive(id string) (*Bead, error) {
163		if b, err := s.Get(context.Background(), id); err == nil {
164			return b, nil
165		}
166		if s.Collection != DefaultCollection {
167			return nil, fmt.Errorf("bead: not found: %s", id)
168		}
169		archive := s.archivePartner()
170		b, err := archive.Get(context.Background(), id)
171		if err != nil {
172			return nil, fmt.Errorf("bead: not found: %s", id)
173		}
174		return b, nil
175	}
