177	// ListWithArchive returns the union of active and archive beads filtered
178	// the same way as List. Active records take precedence over archive
179	// duplicates that may exist after an interrupted archive run.
180	func (s *Store) ListWithArchive(status, label string, where map[string]string) ([]Bead, error) {
181		active, err := s.List(status, label, where)
182		if err != nil {
183			return nil, err
184		}
185		if s.Collection != DefaultCollection {
186			return active, nil
187		}
188		archive := s.archivePartner()
189		archived, err := archive.List(status, label, where)
190		if err != nil {
191			// Archive may not exist yet — treat as empty.
192			return active, nil //nolint:nilerr
193		}
194		seen := make(map[string]bool, len(active))
195		out := make([]Bead, 0, len(active)+len(archived))
196		for _, b := range active {
197			seen[b.ID] = true
198			out = append(out, b)
199		}
200		for _, b := range archived {
201			if seen[b.ID] {
202				continue
203			}
204			out = append(out, b)
205		}
206		return out, nil
207	}
