209	// maybeOpportunisticMaintenance runs the same size-triggered maintenance as
210	// `ddx bead archive` after close-causing mutations: if active beads.jsonl is
211	// over the default 4 MiB threshold, closed-bead events are externalized and
212	// eligible closed rows move to beads-archive. Errors are swallowed because
213	// maintenance must not fail the close that triggered it.
214	func (s *Store) maybeOpportunisticMaintenance() {
215		if s.Collection != DefaultCollection {
216			return
217		}
218		info, err := os.Stat(s.File)
219		if err != nil || info.Size() <= DefaultArchiveSizeThreshold {
220			return
221		}
222		_, _ = s.ArchiveWithEvents(ArchivePolicy{
223			Statuses: []string{StatusClosed},
224		})
225	}
