387	// demonstrating that review-finding beads can be injected, queried, and have their
388	// payloads preserved for later processing by the execute loop.
389	func TestInjectReviewFindingFullLifecycle(t *testing.T) {
390		dir := t.TempDir()
391		store := NewStore(dir)
392	
393		// Create a parent bead (simulating a completed work item).
394		parent := &Bead{
395			ID:        "parent-work-item-001",
396			Title:     "Completed Task",
397			Status:    StatusClosed,
398			IssueType: "task",
399			CreatedAt: time.Now().UTC(),
400			UpdatedAt: time.Now().UTC(),
401		}
402		if err := store.Create(parent); err != nil {
403			t.Fatalf("Create parent: %v", err)
404		}
405	
406		ctx := context.Background()
407	
408		// Inject a review-finding bead (as would be done by an external review system
409		// calling Store.Inject with a ReviewFindingPayload after the parent completes).
410		reviewPayload := &ReviewFindingPayload{
411			Verdict:    "REQUEST_CHANGES",
412			Findings:   "Code review identified several areas for improvement",
413			ResultRev:  "abc123def456",
414			ReviewedBy: "alice@example.com",
415		}
416	
417		reviewID, err := store.Inject(ctx, parent.ID, reviewPayload, InjectOptions{
418			Title:       "Code Review Findings",
419			Description: "Findings from automated code review",
420			Labels:      []string{"kind:review-finding", "source:automated"},
421			Priority:    1,
422		})
423		if err != nil {
424			t.Fatalf("Inject review-finding: %v", err)
425		}
426	
427		// Retrieve the injected bead and verify its properties.
428		bead, err := store.Get(reviewID)
429		if err != nil {
430			t.Fatalf("Get injected bead: %v", err)
431		}
432	
433		// Verify bead metadata.
434		if bead.IssueType != IssueTypeReviewFinding {
435			t.Errorf("expected kind=%s, got %s", IssueTypeReviewFinding, bead.IssueType)
436		}
437		if bead.Status != StatusOpen {
438			t.Errorf("expected status=%s, got %s", StatusOpen, bead.Status)
439		}
440		if bead.Parent != parent.ID {
441			t.Errorf("expected parent=%s, got %s", parent.ID, bead.Parent)
442		}
443		if bead.Title != "Code Review Findings" {
444			t.Errorf("expected title preserved, got %s", bead.Title)
445		}
446	
447		// Verify payload is stored and can be extracted.
448		if bead.Extra == nil {
449			t.Fatalf("bead.Extra is nil, cannot extract payload")
450		}
451	
452		payloadData, ok := bead.Extra["payload"]
453		if !ok {
454			t.Fatalf("payload not found in bead.Extra")
455		}
456	
457		payloadMap, ok := payloadData.(map[string]interface{})
458		if !ok {
459			t.Fatalf("payload has unexpected type: %T", payloadData)
460		}
461	
462		// Verify all payload fields are preserved for execute-loop processing.
463		if v, ok := payloadMap["verdict"]; !ok || v != "REQUEST_CHANGES" {
464			t.Errorf("verdict not preserved: %v", v)
465		}
466		if v, ok := payloadMap["findings"]; !ok || v != "Code review identified several areas for improvement" {
467			t.Errorf("findings not preserved: %v", v)
468		}
469		if v, ok := payloadMap["result_rev"]; !ok || v != "abc123def456" {
470			t.Errorf("result_rev not preserved: %v", v)
471		}
472		if v, ok := payloadMap["reviewed_by"]; !ok || v != "alice@example.com" {
473			t.Errorf("reviewed_by not preserved: %v", v)
474		}
475	
476		// Test idempotency: injecting the same payload again should return the same ID.
477		reviewID2, err := store.Inject(ctx, parent.ID, reviewPayload, InjectOptions{
478			Title: "Code Review Findings",
479		})
480		if err != nil {
481			t.Fatalf("Second inject: %v", err)
482		}
483		if reviewID2 != reviewID {
484			t.Errorf("expected idempotent ID %s, got %s", reviewID, reviewID2)
485		}
486	
487		// Verify that all beads from this parent can be queried.
488		all, err := store.ReadAll(ctx)
489		if err != nil {
490			t.Fatalf("ReadAll: %v", err)
491		}
492	
493		var reviewBeads int
494		for _, b := range all {
495			if b.Parent == parent.ID && b.IssueType == IssueTypeReviewFinding {
496				reviewBeads++
497			}
498		}
499		if reviewBeads != 1 {
500			t.Errorf("expected 1 review-finding bead for parent, got %d", reviewBeads)
501		}
502	}
